var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"가람아.","JPN":"ヒカリ。","ENG":"Garam.","TWN":"嘉蘭。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"관둔다면서……? 회사…… 아카데미도.","JPN":"やめるの……？　会社……アカデミーも。","ENG":"I heard you were quitting... The company... and the Academy.","TWN":"聽說你要辭職……？公司……還有學院。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저 같은 사람, 누가 원하겠어요?","JPN":"だって私みたいな人間はどこからも歓迎されませんから。","ENG":"Who would want someone like me?","TWN":"像我這樣的人，誰會想要呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……결국 선배가 옳았어요.","JPN":"……結局、先輩が正しかったです。","ENG":"...In the end, you were right.","TWN":"……結果還是前輩說得對。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"제가 지금까지 이뤄낸 것들은 전부 선배가 곁에 있어 준 덕이었어요.","JPN":"私が今まで成し遂げたことはすべて、先輩が側にいてくれたからできたことです。","ENG":"Everything that I have accomplished until now was because you were there with me.","TWN":"我至今取得的所有成就，都是因為有前輩在我身邊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"전…… 그게 제 능력이라고 생각했죠.","JPN":"私は……それが自分の能力なんだと勘違いしてました。","ENG":"And I... foolishly thought that it was my abilities.","TWN":"我……以為那就是我的能力。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이번 사고도 모두가 아니었으면 해결하지 못했을 거예요.","JPN":"今回の事故も、皆の力がなければ解決できなかったはずです。","ENG":"Even this incident couldn't have been resolved without everyone's help.","TWN":"這次事故如果沒有大家的幫助，是無法解決的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……그렇지 않아.","JPN":"……そんなことない。","ENG":"...That's not true.","TWN":"……不是這樣的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"힘들었을 거야…… 네가 없었으면.","JPN":"難しかったと思う……ヒカリがいなかったら。","ENG":"It would've been difficult... if you weren't there.","TWN":"一定會很辛苦……要是沒有你。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"받으러 가는 거지……? 조사. 관리국에.","JPN":"受けに行くんだよね……？　調査……管理局に。","ENG":"You're going to the Administration...? For questioning.","TWN":"要去管理局接受調查？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네. 아티팩트와 관련된 사고니까요. 유저들의 소송 건도 있고요.","JPN":"はい。アーティファクト関連の事故ですから。ユーザーの訴訟もありますし。","ENG":"Yes. It was an Artifact-related incident after all. And there are lawsuits from the players as well.","TWN":"是的，與神器相關的事故，還有玩家的訴訟案件。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"도와줄게…… 내가 할 수 있는 일이 있다면.","JPN":"力を貸すよ……私にできることがあれば。","ENG":"I'll help... With whatever I can.","TWN":"我會幫你的……只要是我能做的事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……이만 가볼게요. 더 이상 선배 얼굴을 못 보겠어요.","JPN":"……そろそろ行きますね。これ以上先輩の顔を見ているのも辛いので。","ENG":"...I best get going. I'm too ashamed to even look at your face right now.","TWN":"……我先走了，我已經沒臉見前輩你了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"지금까지 정말 고마웠어요.","JPN":"今までありがとうございました。","ENG":"Thank you for everything.","TWN":"一直以來真的謝謝你。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……아니.","JPN":"……ううん。","ENG":"...No.","TWN":"……不。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"이런 식의 이별은…… 이제 싫어.","JPN":"こんな別れは……もういやだ。","ENG":"I don't like... these kinds of goodbyes.","TWN":"這樣的離別……我已經受夠了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배……?","JPN":"先輩……","ENG":"Naielle...","TWN":"前輩……？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"찾아와…… 조사 끝나면.","JPN":"会いに来て……調査が終わったら。","ENG":"Come back... once the investigation is over.","TWN":"調查結束後……來找我。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아니면…… 내가 찾아갈 테니까.","JPN":"来ないと……私が会いに行くから。","ENG":"Or... I'll come find you.","TWN":"不然……我去找你吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"미안해요 선배…… 선배를 다시 보진 못할 것 같아요.","JPN":"ごめんなさい、先輩……もう先輩に会うことはないと思います。","ENG":"I'm sorry, Bora... but I don't think we'll be seeing each other again.","TWN":"對不起，前輩……我可能再也見不到你了。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……더는 이 일을 하지 못할 테니까요.","JPN":"……この仕事はもうできないから。","ENG":"...Because I won't be able to do this kind of work anymore.","TWN":"……我不能再做這件事了。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"조사가 끝나면 전 고향에 내려가서…….","JPN":"調査が終わったら、故郷に帰って……","ENG":"I'm going to head back home once the investigation is done…","TWN":"調查結束後，我要回老家……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"哎呀！"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"어이쿠! 죄송합니다. 괜찮으신가요?","JPN":"おっと！　すみません。大丈夫ですか？","ENG":"Oh! I'm sorry. Are you all right?","TWN":"啊，對不起！你沒事吧？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"괘, 괜찮아요.","JPN":"だ、大丈夫です。","ENG":"I-I'm okay.","TWN":"你，你沒事吧？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"어라? 그 복장은 혹시, 샐러리맨X……?!","JPN":"あれ？　その格好はもしかして、サラリーマンX……！？","ENG":"Huh? That outfit. Are you... Salaryman X...?!","TWN":"咦？那身裝扮，難道是上班族X……？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"음? 아가씨야말로 오피스레이디Y와 똑 닮았군요?","JPN":"うむ？　お嬢さんこそ、オフィスレディーYとそっくりですね。","ENG":"Hmm? And you seem exactly like Office Lady Y.","TWN":"嗯？小姐你和上班女郎Y一模一樣啊？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"이런 곳에서 스트리트 카운터의 팬을 만나게 될 줄이야!","JPN":"こんなところでストリート・カウンターのファンに出会うとは！","ENG":"I never thought I'd bump into a fan of Street Counter in a place like this!","TWN":"沒想到會在這種地方遇到街頭制裁者的粉絲！"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L45_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"전 김철수라고 합니다. 그쪽은?","JPN":"私はタナカ・ジロウと申します。そちらは？","ENG":"My name is Kim Chulsoo. And you are?","TWN":"我叫金哲洙，你呢？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"서가람이예요…….","JPN":"カワセ・ヒカリです……","ENG":"Seo Garam...","TWN":"我是徐嘉蘭……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"그렇군요. 가람 씨는 어쩌다 오피스레이디Y의 복장을 하게 된 건가요?","JPN":"そうですか。カワセさんはなぜオフィスレディーYの格好を？","ENG":"I see. May I ask why you are dressed as Office Lady Y, Ms. Seo?","TWN":"原來如此。你怎麼會穿上上班女郎Y的服裝呢？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저, 저기…… 제가 좀 바빠서…….","JPN":"あ、あの……私、今急いでいて……","ENG":"Erm... I'm a bit busy right now, so...","TWN":"那，那個……我有點忙……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"하하, 죄송합니다. 업무 스트레스가 클 텐데 제가 방해했군요.","JPN":"はは、すみません。とてもお忙しいところを私が邪魔してしまいましたね。","ENG":"Haha, no worries. Work must be stressful, and I seemed to have bothered you.","TWN":"哈哈，對不起。工作壓力很大吧，打擾了。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네, 네……?!","JPN":"え、えっ……？","ENG":"E-excuse me...?!","TWN":"啊？什麼？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"그냥 여기 건물에서 나오시는 걸 보고, 뭔가 대단한 일을 하시는 분이라 생각했을 뿐입니다.","JPN":"いや、この建物から出て来たってことは、何かすごい仕事をされている方だろうと推測しただけです。","ENG":"It's just that I saw you coming out of that building, so I assumed you were doing some amazing work there.","TWN":"只是看到你從這棟建築裡出來，就覺得你在做的事一定很厲害。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아뇨……. 전 구제 불능이에요.","JPN":"いえ……私はダメな人間です。","ENG":"No... I'm as hopeless as one can get.","TWN":"不……已經跟我沒關係了。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"사실 제가 사고를 치는 바람에 회사를 그만두게 됐거든요.","JPN":"実は大きい事故を起こしてしまって、会社をやめることになったんです。","ENG":"Actually, I had to quit my job because I messed up big time.","TWN":"其實是因為我闖了禍，所以才離開公司的。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"아, 죄송합니다. 이럴 의도는 아니었는데…….","JPN":"あ、これは失礼しました。そういうつもりではなかったんですが……","ENG":"Oh, I'm sorry to hear that. I didn't mean to rub salt on your wounds...","TWN":"啊，對不起，我不是故意的……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"괜찮아요. 사실인걸요.","JPN":"いいんです。事実ですから。","ENG":"It's fine. It's the truth.","TWN":"沒關係，確實如此。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"……사실 저도 마찬가지입니다. 일자리 좀 구해보겠다고 여기까지 왔는데, 오늘도 허탕이었거든요.","JPN":"……実は私も同じ状況でして。仕事を探しにここまで来たんですが、今日も空振りでした。","ENG":"...Actually, I'm the same. I came all this way trying to find some work, but it was a bust.","TWN":"……其實我也是一樣的。我為了找工作來到這裡，今天也撲了個空。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"하하, 그래도 간만에 카운터즈 레거시란 게임 덕에 추억도 쌓고 좋았죠.","JPN":"はは、でも久しぶりにカウンターズ・レガシーというゲームのおかげで、思い出ができてよかったです。","ENG":"Haha, but at least I got to relive some old memories through a game called Counters Legacy.","TWN":"哈哈，不過多虧了制裁者的遺產這款遊戲，才讓我積累了不少回憶，真不錯。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"긴급 점검 때문에 서버가 내려갔지만, 정말 좋은 게임이라 생각합니다.","JPN":"緊急メンテナンスでサーバーが落ちましたが、あれは本当にいいゲームだと思いますよ。","ENG":"The server went down because of the emergency maintenance, but I think it's an amazing game.","TWN":"雖然因為緊急維護關閉伺服器，但我認為這真的是一款好遊戲。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"철수 씨…….","JPN":"タナカさん……","ENG":"Mr. Kim...","TWN":"哲洙……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"저도 이만 실례하겠습니다. 부디 앞으로는 좋은 일 있으셨으면 좋겠네요.","JPN":"ではこれで失礼します。これからはいいことがたくさんあるといいですね。","ENG":"Excuse me. I hope good things are waiting for you in the future.","TWN":"我也告辭了，祝你一切順利。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHEOLSU_YUKSAM_NULL_NULL","text":{"KOREA":"함께 힘내봅시다! 현실은 물론 각박하겠지만, 그걸 정면으로 받아내는 게 샐러리맨과 오피스레이디 아니겠습니까? 하하.","JPN":"一緒に頑張りましょう！　現実は厳しいでしょうが、それに立ち向かってこそサラリーマンとオフィスレディーですよね。ははは。","ENG":"Let's both cheer up! Reality might be harsh, but don't Salaryman X and Office Lady Y face them head-on? Haha!","TWN":"一起加油吧！雖然現實可能很殘酷，但正面迎接挑戰不正是上班族的本色嗎？哈哈。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_YUKSAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"잘 얘기하고 왔어?","JPN":"ちゃんと話してきたの？","ENG":"Did you talk to them?","TWN":"談得順利嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"다른 사람 임용할 거지……? 빈자리.","JPN":"他の人、採用するんだよね……？　欠員。","ENG":"You're going to hire someone else, right...? For the vacancy.","TWN":"會請其他人吧……？空缺的位置。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"보라는 어떻게 했으면 좋겠어?","JPN":"シホちゃんはどうしたい？","ENG":"What do you think, Bora?","TWN":"你希望怎麼做？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……조금만 기다려 줬으면 해.","JPN":"……少しだけ待って欲しい。","ENG":"...I say we wait a little.","TWN":"……希望你能再稍等一會。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"당분간 내가 할 테니까……. 가람이 맡았던 수업도.","JPN":"しばらく私がやるから……ヒカリが担当してた授業も。","ENG":"I'll do it for the time being... Even Garam's classes.","TWN":"暫時由我來負責……還有嘉蘭負責的課程。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"괜찮겠어? 너무 무리한다고 생각하는데.","JPN":"大丈夫なの？　無理しすぎじゃない？","ENG":"Are you sure? Don't push yourself too much.","TWN":"沒關係嗎？我覺得你太勉強了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"기다릴 거야…… 가람이 돌아올 때까지.","JPN":"待つ……ヒカリが帰ってくるまで。","ENG":"I'm going to wait... until Garam comes back.","TWN":"我會等的……直到嘉蘭回來。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"싫다고 하면…… 어쩔 수 없겠지만.","JPN":"いやなら……仕方ないけど。","ENG":"But I can't do anything... if she doesn't want to.","TWN":"如果你不願意……那也沒辦法。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……부탁할게.","JPN":"……お願い。","ENG":"...So, please.","TWN":"……拜託你了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"알았어. 보라가 정 그렇다면.","JPN":"わかった。シホちゃんがそうしたいなら。","ENG":"Okay. If that's what you want.","TWN":"知道了，你都這麼說了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"많이 곤란한 모양이네 니들.","JPN":"ずいぶん困ってるみたいやな。","ENG":"Seems like you're all in a bit of a pickle.","TWN":"你們看起來很為難呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"역시 이러고 있을 줄 알았다. 그래가꼬 내 맘 편히 떠날 수 있겠나?","JPN":"こうなってると思ったわ。こんなんじゃおちおち旅立つこともでけへん。","ENG":"I knew y'all would be like this. So, how am I supposed to leave with a peace of mind?","TWN":"我就知道你會這樣，這樣我能安心離開嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"리, 리네야……?!","JPN":"マ、マリちゃん…！？","ENG":"R-Rinae...?!","TWN":"璃奈……？！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내 결심했다. 당분간 여기 신세 좀 지려는데 괜찮지?","JPN":"決めた。しばらくここで世話になるけど、ええな？","ENG":"I made up my mind to stay here for a little while. Is that fine with y'all?","TWN":"我已經決定了，暫時在這裡借住一段時間，可以嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"신세……? 하던 일은……?","JPN":"世話になる……？　仕事は……？","ENG":"Stay...? What about what you were working on...?","TWN":"暫住……？工作呢……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 그건 내 알아서 할 게.","JPN":"あはは、それはなんとでもなる。","ENG":"Ah hah hah, let me worry 'bout that.","TWN":"哈哈哈，那你就別管了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"관심이 생겼거든. 은퇴도 했고, 이제 슬슬 제자 육성을 해보고 싶어졌다.","JPN":"興味が湧いたんや。引退もしたし、そろそろ弟子を育てたいなぁと思ってな。","ENG":"I found a new interest. I've retired, and it's 'bout time I trained some disciples.","TWN":"既然已經退休了，我現在也想慢慢培養一些徒弟。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"우리의 뒤를 이을…… 새로운 시대의 카운터를.","JPN":"ウチらの後を継ぐ……新たな時代のカウンターを。","ENG":"A new age of Counters... who will succeed us.","TWN":"繼承我們的……新世代的制裁者。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};